<boltAction type="file" filePath="fishhunt/app/Models/User.php" contentType="text/x-php">
<?php

namespace App\Models;

use Illuminate\Database\Eloquent\Factories\HasFactory;
use Illuminate\Database\Eloquent\Relations\BelongsToMany;
use Illuminate\Database\Eloquent\Relations\HasMany;
use Illuminate\Foundation\Auth\User as Authenticatable;
use Illuminate\Notifications\Notifiable;

class User extends Authenticatable
{
    use HasFactory, Notifiable;

    protected $fillable = [
        'name', 'email', 'password', 'avatar', 'bio', 'location', 'catches_count',
    ];

    protected $hidden = ['password', 'remember_token'];

    protected function casts(): array
    {
        return [
            'email_verified_at' => 'datetime',
            'password' => 'hashed',
        ];
    }

    public function roles(): BelongsToMany
    {
        return $this->belongsToMany(Role::class);
    }

    public function catches(): HasMany
    {
        return $this->hasMany(CatchPost::class);
    }

    public function huntPlans(): HasMany
    {
        return $this->hasMany(HuntPlan::class);
    }

    public function comments(): HasMany
    {
        return $this->hasMany(Comment::class);
    }

    public function likes(): HasMany
    {
        return $this->hasMany(Like::class);
    }

    public function reports(): HasMany
    {
        return $this->hasMany(Report::class);
    }

    public function hasRole(string $slug): bool
    {
        return $this->roles()->where('slug', $slug)->exists();
    }

    public function hasPermission(string $slug): bool
    {
        return $this->roles()->whereHas('permissions', function ($q) use ($slug) {
            $q->where('slug', $slug);
        })->exists();
    }

    public function isAdmin(): bool
    {
        return $this->hasRole('admin');
    }

    public function isMod(): bool
    {
        return $this->hasRole('moderator') || $this->isAdmin();
    }

    public function getAvatarUrlAttribute(): string
    {
        if ($this->avatar) {
            return asset('storage/' . $this->avatar);
        }
        return 'https://ui-avatars.com/api/?name=' . urlencode($this->name) . '&background=6366f1&color=fff&size=128';
    }

    public function getInitialsAttribute(): string
    {
        $words = explode(' ', $this->name);
        $initials = '';
        foreach (array_slice($words, 0, 2) as $word) {
            $initials .= strtoupper(substr($word, 0, 1));
        }
        return $initials;
    }
}
</boltAction>

<boltAction type="file" filePath="fishhunt/app/Models/CatchPost.php" contentType="text/x-php">
<?php

namespace App\Models;

use Illuminate\Database\Eloquent\Model;
use Illuminate\Database\Eloquent\Relations\BelongsTo;
use Illuminate\Database\Eloquent\Relations\HasMany;
use Illuminate\Database\Eloquent\Relations\MorphMany;

class CatchPost extends Model
{
    protected $table = 'catches';

    protected $fillable = [
        'user_id', 'species', 'weight', 'length', 'location',
        'latitude', 'longitude', 'description', 'technique',
        'bait', 'weather_conditions', 'caught_at', 'is_released', 'is_featured',
    ];

    protected function casts(): array
    {
        return [
            'caught_at' => 'datetime',
            'is_released' => 'boolean',
            'is_featured' => 'boolean',
            'weight' => 'decimal:2',
            'length' => 'decimal:2',
            'latitude' => 'decimal:7',
            'longitude' => 'decimal:7',
        ];
    }

    public function user(): BelongsTo
    {
        return $this->belongsTo(User::class);
    }

    public function photos(): HasMany
    {
        return $this->hasMany(CatchPhoto::class, 'catch_id');
    }

    public function primaryPhoto()
    {
        return $this->hasOne(CatchPhoto::class, 'catch_id')->where('is_primary', true);
    }

    public function likes(): MorphMany
    {
        return $this->morphMany(Like::class, 'likeable');
    }

    public function comments(): MorphMany
    {
        return $this->morphMany(Comment::class, 'commentable');
    }

    public function reports(): MorphMany
    {
        return $this->morphMany(Report::class, 'reportable');
    }

    public function isLikedBy(?User $user): bool
    {
        if (!$user) return false;
        return $this->likes()->where('user_id', $user->id)->exists();
    }

    public function getPhotoUrlAttribute(): string
    {
        $photo = $this->primaryPhoto;
        if ($photo) {
            return asset('storage/' . $photo->path);
        }
        return $this->getDefaultPhotoUrl();
    }

    private function getDefaultPhotoUrl(): string
    {
        $photos = [
            'https://images.pexels.com/photos/1630344/pexels-photo-1630344.jpeg?auto=compress&cs=tinysrgb&w=800',
            'https://images.pexels.com/photos/1906153/pexels-photo-1906153.jpeg?auto=compress&cs=tinysrgb&w=800',
            'https://images.pexels.com/photos/2131967/pexels-photo-2131967.jpeg?auto=compress&cs=tinysrgb&w=800',
            'https://images.pexels.com/photos/1078074/pexels-photo-1078074.jpeg?auto=compress&cs=tinysrgb&w=800',
        ];
        return $photos[$this->id % count($photos)];
    }
}
</boltAction>

