<?php

namespace App\Services;

class DemoDataService
{
    public static function getWeatherData(string $location, string $date): array
    {
        $conditions = ['Sunny', 'Partly Cloudy', 'Overcast', 'Light Rain', 'Clear Skies', 'Foggy Morning'];
        $hash = crc32($location . $date);

        return [
            'condition' => $conditions[abs($hash) % count($conditions)],
            'temperature' => rand(55, 85),
            'humidity' => rand(40, 90),
            'wind_speed' => rand(2, 25),
            'wind_direction' => ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'][abs($hash) % 8],
            'pressure' => round(29.5 + (rand(0, 100) / 100), 2),
            'uv_index' => rand(1, 11),
            'sunrise' => '6:' . str_pad(rand(0, 30), 2, '0', STR_PAD_LEFT) . ' AM',
            'sunset' => '7:' . str_pad(rand(15, 55), 2, '0', STR_PAD_LEFT) . ' PM',
            'moon_phase' => ['New Moon', 'Waxing Crescent', 'First Quarter', 'Waxing Gibbous', 'Full Moon', 'Waning Gibbous', 'Last Quarter', 'Waning Crescent'][abs($hash) % 8],
            'forecast' => [
                ['hour' => '6 AM', 'temp' => rand(50, 65), 'condition' => 'Clear'],
                ['hour' => '9 AM', 'temp' => rand(60, 72), 'condition' => 'Partly Cloudy'],
                ['hour' => '12 PM', 'temp' => rand(70, 85), 'condition' => $conditions[abs($hash + 1) % count($conditions)]],
                ['hour' => '3 PM', 'temp' => rand(72, 88), 'condition' => $conditions[abs($hash + 2) % count($conditions)]],
                ['hour' => '6 PM', 'temp' => rand(65, 78), 'condition' => 'Clear'],
            ],
        ];
    }

    public static function getTideData(string $location, string $date): array
    {
        $hash = crc32($location . $date);
        $baseHour = abs($hash) % 6;

        return [
            'station' => $location . ' Harbor',
            'tides' => [
                ['type' => 'Low', 'time' => ($baseHour) . ':' . str_pad(rand(0, 59), 2, '0', STR_PAD_LEFT) . ' AM', 'height' => round(rand(5, 20) / 10, 1) . ' ft'],
                ['type' => 'High', 'time' => ($baseHour + 6) . ':' . str_pad(rand(0, 59), 2, '0', STR_PAD_LEFT) . ' AM', 'height' => round(rand(40, 70) / 10, 1) . ' ft'],
                ['type' => 'Low', 'time' => ($baseHour < 6 ? $baseHour + 12 : $baseHour + 6) . ':' . str_pad(rand(0, 59), 2, '0', STR_PAD_LEFT) . ' PM', 'height' => round(rand(5, 25) / 10, 1) . ' ft'],
                ['type' => 'High', 'time' => '8:' . str_pad(rand(0, 59), 2, '0', STR_PAD_LEFT) . ' PM', 'height' => round(rand(35, 65) / 10, 1) . ' ft'],
            ],
            'current' => [
                'direction' => ['Incoming', 'Outgoing', 'Slack'][abs($hash) % 3],
                'speed' => round(rand(5, 30) / 10, 1) . ' knots',
