<boltAction type="file" filePath="fishhunt/app/Http/Controllers/CatchController.php" contentType="text/x-php">
<?php

namespace App\Http\Controllers;

use App\Models\CatchPost;
use App\Models\CatchPhoto;
use App\Services\DemoDataService;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\Storage;

class CatchController extends Controller
{
    public function index(Request $request)
    {
        $catches = $request->user()->catches()
            ->with('photos')
            ->withCount(['likes', 'comments'])
            ->latest()
            ->paginate(12);

        return view('catches.index', compact('catches'));
    }

    public function create()
    {
        $species = DemoDataService::getAllSpeciesList();
        return view('catches.create', compact('species'));
    }

    public function store(Request $request)
    {
        $validated = $request->validate([
            'species' => 'required|string|max:255',
            'weight' => 'nullable|numeric|min:0|max:9999',
            'length' => 'nullable|numeric|min:0|max:999',
            'location' => 'required|string|max:255',
            'latitude' => 'nullable|numeric|between:-90,90',
            'longitude' => 'nullable|numeric|between:-180,180',
            'description' => 'nullable|string|max:2000',
            'technique' => 'nullable|string|max:255',
            'bait' => 'nullable|string|max:255',
            'weather_conditions' => 'nullable|string|max:255',
            'caught_at' => 'required|date|before_or_equal:now',
            'is_released' => 'boolean',
            'photos.*' => 'image|mimes:jpeg,png,jpg,webp|max:5120',
        ]);

        $validated['user_id'] = $request->user()->id;
        $validated['is_released'] = $request->boolean('is_released');

        $catch = CatchPost::create($validated);

        if ($request->hasFile('photos')) {
            foreach ($request->file('photos') as $index => $photo) {
                $path = $photo->store('catches/' . $catch->id, 'public');
                CatchPhoto::create([
                    'catch_id' => $catch->id,
                    'path' => $path,
                    'filename' => $photo->getClientOriginalName(),
                    'is_primary' => $index === 0,
                    'sort_order' => $index,
                ]);
            }
        }

        $request->user()->increment('catches_count');

        return redirect()->route('catches.show', $catch)->with('success', 'Catch posted successfully! 🎣');
    }

    public function show(CatchPost $catch)
    {
        $catch->load(['user', 'photos', 'comments.user', 'comments.replies.user', 'likes']);
        $catch->loadCount(['likes', 'comments']);

        return view('catches.show', compact('catch'));
    }

    public function edit(CatchPost $catch)
    {
        $this->authorize('update', $catch);
        $species = DemoDataService::getAllSpeciesList();
        return view('catches.edit', compact('catch', 'species'));
    }

    public function update(Request $request, CatchPost $catch)
    {
        $this->authorize('update', $catch);

        $validated = $request->validate([
            'species' => 'required|string|max:255',
            'weight' => 'nullable|numeric|min:0|max:9999',
            'length' => 'nullable|numeric|min:0|max:999',
            'location' => 'required|string|max:255',
            'description' => 'nullable|string|max:2000',
            'technique' => 'nullable|string|max:255',
            'bait' => 'nullable|string|max:255',
            'weather_conditions' => 'nullable|string|max:255',
            'caught_at' => 'required|date|before_or_equal:now',
            'is_released' => 'boolean',
        ]);

        $validated['is_released'] = $request->boolean('is_released');
        $catch->update($validated);

        return redirect()->route('catches.show', $catch)->with('success', 'Catch updated!');
    }

    public function destroy(CatchPost $catch)
    {
        $this->authorize('delete', $catch);

        foreach ($catch->photos as $photo) {
            Storage::disk('public')->delete($photo->path);
        }

        $catch->user->decrement('catches_count');
        $catch->delete();

        return redirect()->route('catches.index')->with('success', 'Catch deleted.');
    }

    public function toggleFeature(CatchPost $catch)
    {
        $this->authorize('feature', $catch);
        $catch->update(['is_featured' => !$catch->is_featured]);

        return back()->with('success', $catch->is_featured ? 'Catch featured!' : 'Catch unfeatured.');
    }
}
