{
    public function store(Request $request)
    {
        $validated = $request->validate([
            'reportable_type' => 'required|in:catch,comment',
            'reportable_id' => 'required|integer',
            'reason' => 'required|string|max:255',
            'details' => 'nullable|string|max:2000',
        ]);

        $type = $validated['reportable_type'] === 'catch' ? CatchPost::class : Comment::class;
        $model = $type::findOrFail($validated['reportable_id']);

        Report::create([
            'user_id' => $request->user()->id,
            'reportable_type' => $type,
            'reportable_id' => $model->id,
            'reason' => $validated['reason'],
            'details' => $validated['details'],
        ]);

        return back()->with('success', 'Report submitted. Our moderators will review it.');
    }

    public function index(Request $request)
    {
        $reports = Report::with(['user', 'reportable', 'reviewer'])
            ->when($request->status, fn($q, $s) => $q->where('status', $s))
            ->latest()
            ->paginate(20);

        return view('admin.reports', compact('reports'));
