        return redirect()->route('plans.index')->with('success', 'Plan deleted.');
    }

    public function updateChecklist(Request $request, HuntPlan $plan)
    {
        $this->authorize('update', $plan);

        $validated = $request->validate([
            'checklist' => 'required|array',
            'checklist.*.item' => 'required|string',
            'checklist.*.checked' => 'required|boolean',
            'checklist.*.category' => 'required|string',
        ]);

        $plan->update(['checklist' => $validated['checklist']]);

        return response()->json(['success' => true, 'progress' => $plan->checklist_progress]);
    }

    public function regenerateBriefing(HuntPlan $plan)
    {
        $this->authorize('update', $plan);

        $plan->update([
            'weather_data' => DemoDataService::getWeatherData($plan->location, $plan->planned_date->format('Y-m-d')),
            'tide_data' => DemoDataService::getTideData($plan->location, $plan->planned_date->format('Y-m-d')),
            'species_data' => $plan->target_species
                ? DemoDataService::getSpeciesData($plan->target_species, $plan->location)
                : null,
        ]);

        return back()->with('success', 'Briefing data refreshed!');
    }
}
</boltAction>

<boltAction type="file" filePath="fishhunt/app/Http/Controllers/AdminController.php" contentType="text/x-php">
<?php

namespace App\Http\Controllers;

use App\Models\CatchPost;
use App\Models\Comment;
use App\Models\HuntPlan;
use App\Models\Report;
use App\Models\User;
use Illuminate\Http\Request;

class AdminController extends Controller
{
    public function dashboard()
    {
        $stats = [
            'users' => User::count(),
            'catches' => CatchPost::count(),
            'comments' => Comment::count(),
            'plans' => HuntPlan::count(),
            'pending_reports' => Report::where('status', 'pending')->count(),
        ];

        $recentUsers = User::latest()->take(5)->get();
        $recentReports = Report::with(['user', 'reportable'])->where('status', 'pending')->latest()->take(10)->get();

        return view('admin.dashboard', compact('stats', 'recentUsers', 'recentReports'));
    }

    public function users(Request $request)
    {
        $users = User::with('roles')
            ->when($request->search, fn($q, $s) => $q->where('name', 'ilike', "%{$s}%")->orWhere('email', 'ilike', "%{$s}%"))
            ->latest()
            ->paginate(20);

        return view('admin.users', compact('users'));
    }

    public function updateUserRole(Request $request, User $user)
    {
        $validated = $request->validate([
            'role' => 'required|in:admin,moderator,member',
        ]);

        $roleMap = [
            'admin' => 1,
            'moderator' => 2,
            'member' => 3,
        ];

        $user->roles()->sync([$roleMap[$validated['role']]]);

        return back()->with('success', "Role updated for {$user->name}.");
    }
}
</boltAction>

