<boltAction type="file" filePath="fishhunt/app/Http/Controllers/DashboardController.php" contentType="text/x-php">
<?php

namespace App\Http\Controllers;

use App\Models\CatchPost;
use App\Models\HuntPlan;
use Illuminate\Http\Request;

class DashboardController extends Controller
{
    public function __invoke(Request $request)
    {
        $user = $request->user();

        $stats = [
            'total_catches' => $user->catches()->count(),
            'total_species' => $user->catches()->distinct('species')->count('species'),
            'biggest_catch' => $user->catches()->max('weight'),
            'total_plans' => $user->huntPlans()->count(),
            'upcoming_plans' => $user->huntPlans()->where('planned_date', '>=', now())->where('status', '!=', 'cancelled')->count(),
        ];

        $recentCatches = $user->catches()->with('photos', 'user')->latest()->take(5)->get();
        $upcomingPlans = $user->huntPlans()
            ->where('planned_date', '>=', now())
            ->where('status', '!=', 'cancelled')
            ->orderBy('planned_date')
            ->take(5)
            ->get();

        $featuredCatches = CatchPost::with('photos', 'user')
            ->where('is_featured', true)
            ->latest()
            ->take(3)
            ->get();

        return view('dashboard', compact('stats', 'recentCatches', 'upcomingPlans', 'featuredCatches'));
    }
}
