<?php

namespace App\Http\Controllers;

use App\Models\CatchPost;
use Illuminate\Http\Request;

class FeedController extends Controller
{
    public function __invoke(Request $request)
    {
        $query = CatchPost::with(['user', 'photos', 'likes', 'comments'])
            ->withCount(['likes', 'comments']);

        if ($request->filled('species')) {
            $query->where('species', $request->species);
        }

        if ($request->filled('sort')) {
            match ($request->sort) {
                'popular' => $query->orderByDesc('likes_count'),
                'biggest' => $query->orderByDesc('weight'),
                default => $query->latest('caught_at'),
            };
        } else {
            $query->latest('caught_at');
        }

        $catches = $query->paginate(12);

        $species = CatchPost::distinct()->pluck('species')->sort()->values();

        return view('feed.index', compact('catches', 'species'));
    }
}
</boltAction>

