<boltAction type="file" filePath="fishhunt/app/Http/Controllers/LikeController.php" contentType="text/x-php">
<?php

namespace App\Http\Controllers;

use App\Models\CatchPost;
use Illuminate\Http\Request;

class LikeController extends Controller
{
    public function toggle(Request $request, CatchPost $catch)
    {
        $existing = $catch->likes()->where('user_id', $request->user()->id)->first();

        if ($existing) {
            $existing->delete();
            $liked = false;
        } else {
            $catch->likes()->create(['user_id' => $request->user()->id]);
            $liked = true;
        }

        if ($request->wantsJson()) {
            return response()->json([
                'liked' => $liked,
                'count' => $catch->likes()->count(),
            ]);
        }

        return back();
    }
}
