<?php

namespace App\Http\Controllers;

use App\Models\HuntPlan;
use App\Services\DemoDataService;
use Illuminate\Http\Request;

class HuntPlanController extends Controller
{
    public function index(Request $request)
    {
        $plans = $request->user()->huntPlans()
            ->when($request->status, fn($q, $s) => $q->where('status', $s))
            ->orderByDesc('planned_date')
            ->paginate(12);

        return view('plans.index', compact('plans'));
    }

    public function create()
    {
        $species = DemoDataService::getAllSpeciesList();
        $defaultChecklist = DemoDataService::getDefaultChecklist();
        return view('plans.create', compact('species', 'defaultChecklist'));
    }

    public function store(Request $request)
    {
        $validated = $request->validate([
            'title' => 'required|string|max:255',
            'description' => 'nullable|string|max:2000',
            'location' => 'required|string|max:255',
            'latitude' => 'nullable|numeric|between:-90,90',
            'longitude' => 'nullable|numeric|between:-180,180',
            'planned_date' => 'required|date|after_or_equal:today',
            'start_time' => 'nullable|date_format:H:i',
            'end_time' => 'nullable|date_format:H:i',
            'target_species' => 'nullable|array',
            'target_species.*' => 'string|max:255',
            'notes' => 'nullable|string|max:2000',
        ]);

        $validated['user_id'] = $request->user()->id;
        $validated['status'] = 'planned';
        $validated['checklist'] = DemoDataService::getDefaultChecklist();

        // Generate briefing data
        $validated['weather_data'] = DemoDataService::getWeatherData(
            $validated['location'],
            $validated['planned_date']
        );
        $validated['tide_data'] = DemoDataService::getTideData(
            $validated['location'],
            $validated['planned_date']
        );

        if (!empty($validated['target_species'])) {
            $validated['species_data'] = DemoDataService::getSpeciesData(
                $validated['target_species'],
                $validated['location']
            );
        }

        $plan = HuntPlan::create($validated);

        return redirect()->route('plans.show', $plan)->with('success', 'Hunt plan created with full briefing! 🎯');
    }

    public function show(HuntPlan $plan)
    {
        $this->authorize('view', $plan);
        return view('plans.show', compact('plan'));
    }

    public function edit(HuntPlan $plan)
    {
        $this->authorize('update', $plan);
        $species = DemoDataService::getAllSpeciesList();
        return view('plans.edit', compact('plan', 'species'));
    }

    public function update(Request $request, HuntPlan $plan)
    {
        $this->authorize('update', $plan);

        $validated = $request->validate([
            'title' => 'required|string|max:255',
            'description' => 'nullable|string|max:2000',
            'location' => 'required|string|max:255',
            'planned_date' => 'required|date',
            'start_time' => 'nullable|date_format:H:i',
            'end_time' => 'nullable|date_format:H:i',
            'target_species' => 'nullable|array',
            'target_species.*' => 'string|max:255',
            'status' => 'nullable|in:draft,planned,active,completed,cancelled',
            'notes' => 'nullable|string|max:2000',
        ]);

        // Regenerate briefing data
        $validated['weather_data'] = DemoDataService::getWeatherData(
            $validated['location'],
            $validated['planned_date']
        );
        $validated['tide_data'] = DemoDataService::getTideData(
            $validated['location'],
            $validated['planned_date']
        );

        if (!empty($validated['target_species'])) {
            $validated['species_data'] = DemoDataService::getSpeciesData(
                $validated['target_species'],
                $validated['location']
            );
        }

        $plan->update($validated);

        return redirect()->route('plans.show', $plan)->with('success', 'Plan updated!');
    }

    public function destroy(HuntPlan $plan)
    {
        $this->authorize('delete', $plan);
        $plan->delete();

        return redirect()->route('plans.index')->with('success', 'Plan deleted.');
    }

    public function updateChecklist(Request $request, HuntPlan $plan)
    {
        $this->authorize('update', $plan);

        $validated = $request->validate([
            'checklist' => 'required|array',
            'checklist.*.item' => 'required|string',
            'checklist.*.checked' => 'required|boolean',
            'checklist.*.category' => 'required|string',
        ]);

        $plan->update(['checklist' => $validated['checklist']]);

        return response()->json(['success' => true, 'progress' => $plan->checklist_progress]);
    }

    public function regenerateBriefing(HuntPlan $plan)
    {
        $this->authorize('update', $plan);

        $plan->update([
            'weather_data' => DemoDataService::getWeatherData($plan->location, $plan->planned_date->format('Y-m-d')),
            'tide_data' => DemoDataService::getTideData($plan->location, $plan->planned_date->format('Y-m-d')),
            'species_data' => $plan->target_species
                ? DemoDataService::getSpeciesData($plan->target_species, $plan->location)
                : null,
        ]);

        return back()->with('success', 'Briefing data refreshed!');
    }
}
